def check(results, ws):
    import subprocess, sys, json
    for fn in ('calc/tokenizer.py','calc/parser.py','calc/evaluator.py'):
        if not (ws/fn).exists():
            return (False, "missing module: "+fn)
    harness = (
        "import json\n"
        "from calc.evaluator import calc\n"
        "cases = ["
        "  ('2 + 3 * 4', {}, 14.0),"
        "  ('(2 + 3) * 4', {}, 20.0),"
        "  ('2 ** 3 ** 2', {}, 512.0),"
        "  ('-2 ** 2', {}, -4.0),"
        "  ('10 % 3 + 1', {}, 2.0),"
        "  ('100 / 4 / 5', {}, 5.0),"
        "  ('2 * -3', {}, -6.0),"
        "  ('sqrt(9) + max(1, 2, 3)', {}, 6.0),"
        "  ('x*x + y', {'x':3,'y':4}, 13.0),"
        "  ('min(8, 3) + abs(-5)', {}, 8.0),"
        "  ('2 + 3 * (4 - 1) ** 2', {}, 29.0),"
        "]\n"
        "out = []\n"
        "for expr, env, exp in cases:\n"
        "    try:\n"
        "        got = calc(expr, env)\n"
        "        out.append([expr, float(got), exp, abs(float(got)-exp) < 1e-9])\n"
        "    except Exception as e:\n"
        "        out.append([expr, 'ERR:'+type(e).__name__, exp, False])\n"
        "print(json.dumps(out))\n"
    )
    try:
        p = subprocess.run([sys.executable, '-c', harness], cwd=str(ws),
                           capture_output=True, text=True, timeout=60)
    except Exception as e:
        return (False, "run failed: "+str(e))
    if p.returncode != 0:
        tail = p.stderr.strip().splitlines()[-1] if p.stderr.strip() else ('rc=%d' % p.returncode)
        return (False, "exec error: "+tail[:120])
    try:
        rows = json.loads(p.stdout.strip().splitlines()[-1])
    except Exception:
        return (False, "no json out: "+p.stdout.strip()[:120])
    fails = [r for r in rows if not r[3]]
    if fails:
        r = fails[0]
        return (False, "wrong: %s got %r want %r (%d/%d fail)" % (r[0], r[1], r[2], len(fails), len(rows)))
    tok = subprocess.run([sys.executable, '-c', "from calc.tokenizer import tokenize; print(len(tokenize('1+2*3')))"],
                         cwd=str(ws), capture_output=True, text=True, timeout=30)
    if tok.returncode != 0 or not tok.stdout.strip().isdigit() or int(tok.stdout.strip()) < 5:
        return (False, "tokenizer not functional (multi-file split required)")
    return (True, "all %d expressions correct" % len(rows))

