        if c2.get('a') != 1 or c2.get('c') != 3:
            fails.append('recency wrong: a=' + str(c2.get('a')) + ' c=' + str(c2.get('c')))
        c3 = mod.LRUCache(1)
        c3.put('x', 1); c3.put('y', 2)
        if len(c3.d) != 1 or c3.get('x') is not None or c3.get('y') != 2:
            fails.append('cap=1 failed: size=' + str(len(c3.d)) + ' x=' + str(c3.get('x')) + ' y=' + str(c3.get('y')))
    except Exception as e:
