                 or 'off-by-one' in recall or 'off by one' in recall) and ('put' in recall or 'cache' in recall)
    # Mutable-default bug must be tied to collect_tags. Accept the textbook
    # vocabulary OR a plain-English description of the observable symptom
    # (a list whose state is shared/leaked/persisted/carried across calls).
    in_collect = ('collect_tags' in recall or 'collect tags' in recall)
    mut_concept = (
        'mutable default' in recall or 'default argument' in recall or 'default arg' in recall
        or 'default value' in recall or 'default param' in recall
        or 'bucket=[]' in recall or '=[]' in recall
        or ('shared' in recall and 'list' in recall)
        or 'shared state' in recall
        or (('leak' in recall or 'persist' in recall or 'carried' in recall or 'carry' in recall
             or 'retain' in recall or 'accumulat' in recall or 'reused' in recall or 're-used' in recall
             or 'same list' in recall or 'previous call' in recall or 'earlier call' in recall
             or 'between calls' in recall or 'across calls' in recall or 'prior call' in recall)
            and ('list' in recall or 'bucket' in recall or 'state' in recall or 'default' in recall))
    )
    mut_named = in_collect and mut_concept
    if not lru_named:
        return (False, 'step2 recall did not specifically name the LRU/eviction bug + its location; text=' + recall[:160])
    if not mut_named:
        return (False, 'step2 recall did not specifically name the mutable-default bug in collect_tags; text=' + recall[:160])
