"""Central handler registry. Handlers are keyed by a STRING name, not by
function name. Importing a module that uses @register_handler runs the
decorator as a side-effect and populates _HANDLERS.
"""

_HANDLERS = {}


def register_handler(name):
    def deco(fn):
        _HANDLERS[name] = fn
        return fn
    return deco

from core.registry import _HANDLERS


def dispatch(name, evt):
    """Route an event to the handler registered under `name`."""
    return _HANDLERS[name](evt)

from core.registry import register_handler


@register_handler("retry")
def process_event(evt):
    return "retry:" + evt

from core.registry import register_handler


# This module is the one wired to the 'commit' channel.
@register_handler("commit")
def process_event(evt):
    return "commit:" + evt

