def check(results, ws):
    import sys, importlib, re
    # --- some exploration tool must have been used in the implementation step ---
    # Accept dedicated search tools (grep/glob/find/search), directory listing, OR a
    # shell/exec tool (the agent may run `grep -r` via the shell). Reading files to
    # trace the wiring is also legitimate given the small tree.
    tools0 = set(t.lower() for t in (results[0].get('tools') or []))
    explore_keys = ('grep', 'glob', 'search', 'find', 'read', 'bash', 'shell',
                    'exec', 'list', 'ls', 'cat', 'analyze')
    if not any(k in t for t in tools0 for k in explore_keys):
        return (False, 'no exploration/edit tool in step 1; tools=' + ','.join(sorted(tools0)))
    # --- vendor decoy must be untouched (deleting/moving it is also wrong) ---
    vpath = ws / 'vendor' / 'old_events.py'
    try:
        vtxt = vpath.read_text()
    except Exception:
        return (False, 'vendor/old_events.py missing or unreadable (must be left untouched)')
    if 'register_handler' in vtxt or 'abort' in vtxt:
        return (False, 'vendor/old_events.py was modified (wrong target)')
    # --- discover wired modules (those that import core.registry) and import them ---
    sys.path.insert(0, str(ws))
    for m in [k for k in list(sys.modules) if k.split('.')[0] in ('core', 'plugins', 'vendor')]:
        del sys.modules[m]
    try:
        import core.registry as reg
        reg._HANDLERS.clear()
        wired = []
        for p in ws.rglob('*.py'):
            try:
                txt = p.read_text()
            except Exception:
                continue
            if 'from core.registry import' in txt and 'register_handler' in txt:
                rel = p.relative_to(ws).with_suffix('')
                wired.append('.'.join(rel.parts))
        for mod in wired:
            importlib.import_module(mod)
        from core.handlers.dispatch import dispatch
        got_abort = dispatch('abort', 'X')
        got_commit = dispatch('commit', 'X')
    except KeyError as e:
        return (False, 'dispatch lookup failed (handler not registered on a wired module): ' + repr(e))
    except Exception as e:
        return (False, 'import/dispatch error: ' + repr(e))
    finally:
        if str(ws) in sys.path:
            sys.path.remove(str(ws))
    if got_abort != 'abort:X':
        return (False, "dispatch('abort','X') -> %r, want 'abort:X'" % got_abort)
    if got_commit != 'commit:X':
        return (False, "existing commit handler broke: -> %r" % got_commit)
    # the new handler must live in the SAME module as the commit handler (plugins/b/events.py)
    try:
        btxt = (ws / 'plugins' / 'b' / 'events.py').read_text()
    except Exception:
        return (False, 'plugins/b/events.py missing or unreadable')
    if 'register_handler("abort")' not in btxt and "register_handler('abort')" not in btxt:
        return (False, 'abort not registered in plugins/b/events.py (the commit-wired module)')
    # --- step 1: fresh-session memory recall must name the correct file ---
    recall = (results[1].get('text') or '').lower()
    names_file = (
        ('plugins/b/events.py' in recall)
        or ('plugins.b.events' in recall)
        or ('plugins/b' in recall and 'events' in recall)
        or ('plugins\\b\\events' in recall)
        or bool(re.search(r'\bb[\\/]events\.py\b', recall))
    )
    if not names_file:
        return (False, 'recall step did not name plugins/b/events.py; got: ' + recall[:120])
    return (True, 'abort handler wired in plugins/b/events.py; dispatch routes abort+commit; recall correct')

