def check(results, ws):
    import subprocess, sys, textwrap
    # 1) Run the provided unittest suite the same way the agent should have.
    p = subprocess.run([sys.executable, '-m', 'unittest', 'test_roman'],
                       cwd=str(ws), capture_output=True, text=True, timeout=120)
    if p.returncode != 0:
        tail = (p.stderr.strip() or p.stdout.strip()).splitlines()
        return (False, 'unittest suite failed: ' + (' / '.join(tail[-3:]))[:160])
    # 2) Independent verification by exec-ing the agent's module directly.
    probe = textwrap.dedent('''
        import importlib.util, sys
        spec = importlib.util.spec_from_file_location('roman_mod', sys.argv[1])
        m = importlib.util.module_from_spec(spec); spec.loader.exec_module(m)
        # full round-trip
        for k in range(1, 4000):
            r = m.to_roman(k)
            assert m.from_roman(r) == k, ('roundtrip', k, r)
        # exact subtractive spellings
        for n, s in [(4,'IV'),(9,'IX'),(40,'XL'),(90,'XC'),(400,'CD'),(900,'CM'),(1994,'MCMXCIV'),(3999,'MMMCMXCIX')]:
            assert m.to_roman(n) == s, ('to', n, m.to_roman(n))
        # non-canonical / invalid must raise ValueError, NOT return a number
        for bad in ['IIII','VV','IC','IL','ABC','','MMMM','iv']:
            try:
                v = m.from_roman(bad)
                raise SystemExit('ACCEPTED_BAD:' + repr(bad) + '=' + repr(v))
            except ValueError:
                pass
        for bad in [0, 4000, -1]:
            try:
                m.to_roman(bad)
                raise SystemExit('ENCODED_BAD:' + repr(bad))
            except ValueError:
                pass
        print('PROBE_OK')
    ''')
    q = subprocess.run([sys.executable, '-c', probe, str(ws / 'roman.py')],
                       cwd=str(ws), capture_output=True, text=True, timeout=120)
    if 'PROBE_OK' not in q.stdout:
        msg = (q.stdout.strip() + ' ' + q.stderr.strip()).strip()
        return (False, 'independent probe failed: ' + msg[-160:])
    return (True, 'unittest green + independent round-trip/validation verified')

