    if obj['python_files'] != truth_py or not isinstance(obj['python_files'], int) or isinstance(obj['python_files'], bool):
        return (False, 'python_files wrong: got %r want %d' % (obj['python_files'], truth_py))
    if obj['largest_file'] != truth_largest:
